# Mark test function for database access
@pytest.mark.django_db
def test_user_creation():
    user = User.objects.create(email="test@example.com")
    assert user.pk is not None

# For fixtures needing database access
@pytest.fixture
def user(db):  # Request 'db' fixture explicitly
    return User.objects.create(email="test@example.com")

# Testing transactions explicitly
@pytest.mark.django_db(transaction=True)
def test_payment_rollback(transactional_db):
    with pytest.raises(PaymentError):
        PaymentService.process_with_rollback(order, token="failing")
    order.refresh_from_db()
    assert order.status == "pending"  # Verified rolled back

# Testing ID sequences
@pytest.mark.django_db
def test_order_number_auto_increment(django_db_reset_sequences):
    order1 = Order.objects.create(user=user)
    order2 = Order.objects.create(user=user)
    assert order2.id == order1.id + 1  # IDs are sequential

# Missing @pytest.mark.django_db - raises "no database access allowed"
def test_user_creation():
    user = User.objects.create(email="test@example.com")
    assert user.pk is not None

# Fixture missing db parameter - creates data outside transaction
@pytest.fixture
def user():
    return User.objects.create(email="test@example.com")

# tests/conftest.py

@pytest.fixture(scope="session")
def django_db_setup(django_db_setup, django_db_blocker):
    """Load initial data once per test session."""
    with django_db_blocker.unblock():
        from django.core.management import call_command
        call_command("loaddata", "categories.json")

@pytest.fixture(scope="module")
def sample_products(db, product_factory):
    """Create sample products for a test module."""
    return [
        product_factory(name="Laptop", price=999.99),
        product_factory(name="Mouse", price=29.99),
        product_factory(name="Keyboard", price=79.99),
    ]

# tests/conftest.py
import pytest
from rest_framework.test import APIClient


@pytest.fixture
def api_client() -> APIClient:
    """Unauthenticated DRF API client."""
    return APIClient()


@pytest.fixture
def authenticated_client(api_client, user) -> APIClient:
    """API client authenticated as regular user."""
    api_client.force_authenticate(user=user)
    yield api_client
    api_client.force_authenticate(user=None)


@pytest.fixture
def admin_client(api_client, admin_user) -> APIClient:
    """API client authenticated as admin."""
    api_client.force_authenticate(user=admin_user)
    yield api_client
    api_client.force_authenticate(user=None)


@pytest.fixture
def token_client(api_client, user):
    """API client with JWT token authentication."""
    from rest_framework_simplejwt.tokens import RefreshToken

    refresh = RefreshToken.for_user(user)
    api_client.credentials(HTTP_AUTHORIZATION=f"Bearer {refresh.access_token}")
    yield api_client
    api_client.credentials()

# tests/fixtures/orders.py import pytest
@pytest.fixture def order_with_items(order_factory, product_factory): """Order with 3 items ready for checkout.""" products = [product_factory() for _ in range(3)] order = order_factory(items=[ {"product": p, "quantity": 2} for p in products ]) return order
@pytest.fixture def paid_order(order_with_items, payment_factory): """Order with completed payment.""" payment_factory( order=order_with_items, status="completed", amount=order_with_items.total ) order_with_items.status = "paid" order_with_items.save() return order_with_items
@pytest.fixture def shipped_order(paid_order, shipment_factory): """Order that has been shipped.""" shipment_factory( order=paid_order, tracking_number="TRACK123", carrier="FedEx" ) paid_order.status = "shipped" paid_order.save() return paid_order
# tests/integration/test_fulfillment.py def test_fulfill_paid_order(paid_order): """Only paid orders can be fulfilled.""" result = fulfill_order(paid_order) assert result.status == "shipped"

""" Root conftest.py - Shared fixtures for all tests. """ import pytest from rest_framework.test import APIClient
# Register factories from pytest_factoryboy import register from tests.factories.users import UserFactory, AdminUserFactory from tests.factories.orders import ProductFactory, OrderFactory
register(UserFactory) register(AdminUserFactory, _name="admin_user") register(ProductFactory) register(OrderFactory)
# API Client Fixtures
@pytest.fixture def api_client() -> APIClient: """Unauthenticated DRF API client.""" return APIClient()
@pytest.fixture def authenticated_client(api_client: APIClient, user) -> APIClient: """API client authenticated as regular user.""" api_client.force_authenticate(user=user) yield api_client api_client.force_authenticate(user=None)
@pytest.fixture def admin_client(api_client: APIClient, admin_user) -> APIClient: """API client authenticated as admin user.""" api_client.force_authenticate(user=admin_user) yield api_client api_client.force_authenticate(user=None)
# Settings Fixtures
@pytest.fixture def settings_debug(settings): """Enable DEBUG mode for a test.""" settings.DEBUG = True return settings
@pytest.fixture def settings_no_celery(settings): """Disable Celery eager mode for async testing.""" settings.CELERY_TASK_ALWAYS_EAGER = False return settings
# Utility Fixtures
@pytest.fixture(autouse=True) def _media_root(tmp_path, settings): """Override MEDIA_ROOT to a tmp dir; prevents writing to real disk.""" settings.MEDIA_ROOT = tmp_path / "media"

"""
Test settings for Django project.
Optimized for fast test execution.
"""
from .base import *  # noqa: F401, F403

DEBUG = False
TEMPLATE_DEBUG = False

# Faster in-memory database
DATABASES = {
    "default": {
        "ENGINE": "django.db.backends.sqlite3",
        "NAME": ":memory:",
        "TEST": {
            "NAME": ":memory:",
        },
    }
}

# Faster password hashing
PASSWORD_HASHERS = [
    "django.contrib.auth.hashers.MD5PasswordHasher",
]

# Email backend - captures sent emails
EMAIL_BACKEND = "django.core.mail.backends.locmem.EmailBackend"

# Celery - run tasks synchronously
CELERY_TASK_ALWAYS_EAGER = True
CELERY_TASK_EAGER_PROPAGATES = True

# Cache - use local memory
CACHES = {
    "default": {
        "BACKEND": "django.core.cache.backends.locmem.LocMemCache",
    }
}

# Disable logging during tests
LOGGING = {
    "version": 1,
    "disable_existing_loggers": True,
    "handlers": {"null": {"class": "logging.NullHandler"}},
    "root": {"handlers": ["null"], "level": "CRITICAL"},
}

