# conftest.py - Session-scoped fixture for expensive setup
@pytest.fixture(scope="session")
def sample_products(django_db_setup, django_db_blocker):
    """Create immutable product data once per test session."""
    with django_db_blocker.unblock():
        return [
            Product.objects.create(name="Laptop", price=999.99),
            Product.objects.create(name="Mouse", price=29.99),
        ]

